using System;

class Program {
  static void BubbleSort(int[] arr) {
    int size = arr.Length;
    for (int i = 0; i < size - 1; i++) {
      for (int j = 0; j < size - i - 1; j++) {
        if (arr[j] > arr[j + 1]) {
          int temp = arr[j];
          arr[j] = arr[j + 1];
          arr[j + 1] = temp;
        }
      }
    }
  }

  static void Main() {
    int[] arr = {64, 34, 25, 12, 22, 11, 90};
    BubbleSort(arr);
    Console.Write("Sorted array: ");
    foreach (int num in arr) {
      Console.Write(num + " ");
    }
    Console.WriteLine();
  }
}
// Output: Sorted array: 11 12 22 25 34 64 90

